// BROKEN: two writes, two systems, no atomicity
@Transactional
public void placeOrder(Order order) {
    orderRepository.save(order);          // (1) commits to the DB
    kafkaTemplate.send("orders", event);  // (2) publishes to the broker
}
// Failure modes:
//  - Crash AFTER (1) before (2): DB has the order, no event published.
//    Inventory/payment never hear about it. Lost update across the system.
//  - Broker up but DB commit later rolls back / network blips on (2):
//    event published for an order that does not durably exist. Phantom.
//  - @Transactional only covers the DB. kafkaTemplate.send is OUTSIDE it.

-- Outbox table: events live in the SAME database as business data
CREATE TABLE outbox (
    id           UUID PRIMARY KEY,
    aggregate_type VARCHAR(255) NOT NULL,   -- e.g. 'Order'
    aggregate_id   VARCHAR(255) NOT NULL,   -- e.g. the order id
    event_type     VARCHAR(255) NOT NULL,   -- e.g. 'OrderCreated'
    payload        JSONB        NOT NULL,   -- serialized event
    created_at     TIMESTAMPTZ  NOT NULL DEFAULT now()
);

-- ONE local transaction: business change + event are atomic together
BEGIN;
  INSERT INTO orders (id, customer_id, total, status)
  VALUES ('o-1001', 'c-42', 129.90, 'PENDING');

  INSERT INTO outbox (id, aggregate_type, aggregate_id, event_type, payload)
  VALUES (
    'e-7af3',
    'Order',
    'o-1001',
    'OrderCreated',
    '{"orderId":"o-1001","customerId":"c-42","total":129.90}'
  );
COMMIT;
-- If COMMIT succeeds, the event WILL be published. If it fails, nothing happened.

interface SagaStep {
  name: string;
  invoke: (ctx: OrderContext) => Promise<void>;     // forward local txn
  compensate: (ctx: OrderContext) => Promise<void>;  // semantic rollback
}

class OrderSagaOrchestrator {
  private readonly steps: SagaStep[] = [
    {
      name: 'CreateOrder',
      invoke: (c) => this.orders.create(c.orderId, c.customerId, c.total),
      compensate: (c) => this.orders.markCancelled(c.orderId),
    },
    {
      name: 'ReservePayment',
      invoke: (c) => this.payments.charge(c.orderId, c.customerId, c.total),
      compensate: (c) => this.payments.refund(c.orderId),
    },
    {
      name: 'ReserveInventory',
      invoke: (c) => this.inventory.reserve(c.orderId, c.items),
      compensate: (c) => this.inventory.release(c.orderId),
    },
  ];

  async run(ctx: OrderContext): Promise<SagaResult> {
    const executed: SagaStep[] = [];
    try {
      for (const step of this.steps) {
        // each invoke is idempotent and keyed by ctx.orderId (saga id)
        await step.invoke(ctx);
        executed.push(step);
        await this.persistSagaState(ctx.orderId, step.name, 'DONE');
      }
      await this.orders.confirm(ctx.orderId);
      return { status: 'COMPLETED' };
    } catch (err) {
      // Compensate in REVERSE order. Compensations must be retriable.
      for (const step of executed.reverse()) {
        await this.compensateWithRetry(step, ctx);
      }
      return { status: 'COMPENSATED', failedAt: (err as Error).message };
    }
  }

  private async compensateWithRetry(step: SagaStep, ctx: OrderContext) {
    for (let attempt = 0; attempt < 5; attempt++) {
      try {
        await step.compensate(ctx);    // idempotent: safe to retry
        return;
      } catch {
        await this.backoff(attempt);
      }
    }
    // Exhausted retries: park for manual intervention, never silently drop.
    await this.deadLetter(ctx.orderId, step.name);
  }
}

@Service
public class InventoryConsumer {

  private final JdbcTemplate jdbc;

  // Idempotent consumer: processed-message table + effect in ONE local txn
  @Transactional
  public void onReserveInventory(ReserveInventoryEvent event) {
    // messageId is stable across redeliveries (e.g. outbox row id / event id)
    int inserted = jdbc.update(
        "INSERT INTO processed_messages(message_id) VALUES (?) " +
        "ON CONFLICT (message_id) DO NOTHING",
        event.getMessageId());

    if (inserted == 0) {
      // Duplicate delivery: we have already applied this event. No-op.
      return;
    }

    // First time we see this message: apply the effect in the SAME txn.
    jdbc.update(
        "UPDATE inventory SET reserved = reserved + ? WHERE sku = ?",
        event.getQuantity(), event.getSku());
    // COMMIT makes 'marked processed' + 'effect applied' atomic.
    // A crash before commit -> message redelivered -> reprocessed cleanly.
  }
}

