type OrderContext = {
  orderId: string;
  customerId: string;
  total: number;
  items: { sku: string; qty: number }[];
};

interface SagaStep {
  name: string;
  invoke: (ctx: OrderContext) => Promise<void>;
  compensate: (ctx: OrderContext) => Promise<void>;
}

class OrderSagaOrchestrator {
  constructor(
    private orders: OrderService,
    private payments: PaymentService,
    private inventory: InventoryService,
    private deadLetterQueue: DeadLetterQueue,
  ) {}

  private steps(): SagaStep[] {
    return [
      {
        name: 'CreateOrder',
        invoke: (c) => this.orders.create(c.orderId, c.customerId, c.total),
        compensate: (c) => this.orders.cancel(c.orderId),
      },
      {
        name: 'ChargePayment',
        invoke: (c) => this.payments.charge(c.orderId, c.customerId, c.total),
        compensate: (c) => this.payments.refund(c.orderId),
      },
      {
        name: 'ReserveInventory',
        invoke: (c) => this.inventory.reserve(c.orderId, c.items),
        compensate: (c) => this.inventory.release(c.orderId),
      },
    ];
  }

  async run(ctx: OrderContext): Promise<{ status: string; failedAt?: string }> {
    const executed: SagaStep[] = [];
    try {
      for (const step of this.steps()) {
        await step.invoke(ctx);          // idempotent, keyed by orderId
        executed.push(step);
      }
      await this.orders.confirm(ctx.orderId);
      return { status: 'COMPLETED' };
    } catch (err) {
      // Compensate executed steps in REVERSE order.
      for (const step of [...executed].reverse()) {
        await this.compensateWithRetry(step, ctx);
      }
      return { status: 'COMPENSATED', failedAt: (err as Error).message };
    }
  }

  private async compensateWithRetry(step: SagaStep, ctx: OrderContext): Promise<void> {
    const maxAttempts = 5;
    for (let attempt = 0; attempt < maxAttempts; attempt++) {
      try {
        await step.compensate(ctx);      // idempotent: safe to repeat
        return;
      } catch (e) {
        await this.sleep(Math.min(2 ** attempt * 100, 5000));
      }
    }
    // Exhausted: park for human intervention, never silently drop.
    await this.deadLetterQueue.park(ctx.orderId, step.name);
  }

  private sleep(ms: number) {
    return new Promise((r) => setTimeout(r, ms));
  }
}

